    12â†’ * top-level directory of the distribution or, alternatively, at
    13â†’ * <http://www.OpenLDAP.org/license.html>.
    14â†’ */
    15â†’
    16â†’#include "portable.h"
    17â†’
    18â†’#include <ac/stdlib.h>
    19â†’#include <ac/string.h>
    20â†’
    21â†’#include "lber-int.h"
    22â†’
    23â†’#ifdef LDAP_MEMORY_TRACE
    24â†’#include <stdio.h>
    25â†’#endif
    26â†’
    27â†’#ifdef LDAP_MEMORY_DEBUG
    28â†’/*
    29â†’ * LDAP_MEMORY_DEBUG should only be enabled for the purposes of
    30â†’ * debugging memory management within OpenLDAP libraries and slapd.
    31â†’ *
    32â†’ * It should only be enabled by an experienced developer as it causes
    33â†’ * the inclusion of numerous assert()'s, many of which may be triggered
    34â†’ * by a perfectly valid program.  If LDAP_MEMORY_DEBUG & 2 is true,
    35â†’ * that includes asserts known to break both slapd and current clients.
    36â†’ *
    37â†’ * The code behind this macro is subject to change as needed to
    38â†’ * support this testing.
    39â†’ */
    40â†’
    41â†’struct ber_mem_hdr {
    42â†’	ber_int_t	bm_top;	/* Pattern to detect buf overrun from prev buffer */
    43â†’	ber_int_t	bm_length; /* Length of user allocated area */
    44â†’#ifdef LDAP_MEMORY_TRACE
    45â†’	ber_int_t	bm_sequence; /* Allocation sequence number */
    46â†’#endif
    47â†’	union bmu_align_u {	/* Force alignment, pattern to detect back clobber */
    48â†’		ber_len_t	bmu_len_t;
    49â†’		ber_tag_t	bmu_tag_t;
    50â†’		ber_int_t	bmu_int_t;
    51â†’
    52â†’		size_t	bmu_size_t;
    53â†’		void *	bmu_voidp;
    54â†’		double	bmu_double;
    55â†’		long	bmu_long;
    56â†’		long	(*bmu_funcp)( double );
    57â†’		unsigned char	bmu_char[4];
    58â†’	} ber_align;
    59â†’#define bm_junk	ber_align.bmu_len_t
    60â†’#define bm_data	ber_align.bmu_char[1]
    61â†’#define bm_char	ber_align.bmu_char
    62â†’};
    63â†’
    64â†’/* Pattern at top of allocated space */
    65â†’#define LBER_MEM_JUNK ((ber_int_t) 0xdeaddada)
    66â†’
    67â†’static const struct ber_mem_hdr ber_int_mem_hdr = { LBER_MEM_JUNK };
    68â†’
    69â†’/* Note sequence and ber_int_meminuse are counters, but are not
    70â†’ * thread safe.  If you want to use these values for multithreaded applications,
    71â†’ * you must put mutexes around them, otherwise they will have incorrect values.
    72â†’ * When debugging, if you sort the debug output, the sequence number will 
    73â†’ * put allocations/frees together.  It is then a simple matter to write a script
    74â†’ * to find any allocations that don't have a buffer free function.
    75â†’ */
    76â†’long ber_int_meminuse = 0;
    77â†’#ifdef LDAP_MEMORY_TRACE
    78â†’static ber_int_t sequence = 0;
    79â†’#endif
    80â†’
    81â†’/* Pattern placed just before user data */
    82â†’static unsigned char toppattern[4] = { 0xde, 0xad, 0xba, 0xde };
    83â†’/* Pattern placed just after user data */
    84â†’static unsigned char endpattern[4] = { 0xd1, 0xed, 0xde, 0xca };
    85â†’
    86â†’#define mbu_len sizeof(ber_int_mem_hdr.ber_align)
    87â†’
    88â†’/* Test if pattern placed just before user data is good */
    89â†’#define testdatatop(val) ( \
    90â†’	*(val->bm_char+mbu_len-4)==toppattern[0] && \
    91â†’	*(val->bm_char+mbu_len-3)==toppattern[1] && \
    92â†’	*(val->bm_char+mbu_len-2)==toppattern[2] && \
    93â†’	*(val->bm_char+mbu_len-1)==toppattern[3] )
    94â†’
    95â†’/* Place pattern just before user data */
    96â†’#define setdatatop(val)	*(val->bm_char+mbu_len-4)=toppattern[0]; \
    97â†’	*(val->bm_char+mbu_len-3)=toppattern[1]; \
    98â†’	*(val->bm_char+mbu_len-2)=toppattern[2]; \
    99â†’	*(val->bm_char+mbu_len-1)=toppattern[3];
   100â†’
   101â†’/* Test if pattern placed just after user data is good */
   102â†’#define testend(val) ( 	*((unsigned char *)val+0)==endpattern[0] && \
   103â†’	*((unsigned char *)val+1)==endpattern[1] && \
   104â†’	*((unsigned char *)val+2)==endpattern[2] && \
   105â†’	*((unsigned char *)val+3)==endpattern[3] )
   106â†’
   107â†’/* Place pattern just after user data */
   108â†’#define setend(val)  	*((unsigned char *)val+0)=endpattern[0]; \
   109â†’	*((unsigned char *)val+1)=endpattern[1]; \
   110â†’	*((unsigned char *)val+2)=endpattern[2]; \
   111â†’	*((unsigned char *)val+3)=endpattern[3];
   112â†’
   113â†’#define BER_MEM_BADADDR	((void *) &ber_int_mem_hdr.bm_data)
   114â†’#define BER_MEM_VALID(p)	do { \
   115â†’		assert( (p) != BER_MEM_BADADDR );	\
   116â†’		assert( (p) != (void *) &ber_int_mem_hdr );	\
   117â†’	} while(0)
   118â†’
   119â†’#else
   120â†’#define BER_MEM_VALID(p)	/* no-op */
   121â†’#endif
   122â†’
   123â†’BerMemoryFunctions *ber_int_memory_fns = NULL;
   124â†’
   125â†’void
   126â†’ber_memfree_x( void *p, void *ctx )
   127â†’{
   128â†’	if( p == NULL ) {
   129â†’		return;
   130â†’	}
   131â†’
   132â†’	BER_MEM_VALID( p );
   133â†’
   134â†’	if( ber_int_memory_fns == NULL || ctx == NULL ) {
   135â†’#ifdef LDAP_MEMORY_DEBUG
   136â†’		struct ber_mem_hdr *mh = (struct ber_mem_hdr *)
   137â†’			((char *)p - sizeof(struct ber_mem_hdr));
   138â†’		assert( mh->bm_top == LBER_MEM_JUNK);
   139â†’		assert( testdatatop( mh));
   140â†’		assert( testend( (char *)&mh[1] + mh->bm_length) );
   141â†’		ber_int_meminuse -= mh->bm_length;
   142â†’
   143â†’#ifdef LDAP_MEMORY_TRACE
   144â†’		fprintf(stderr, "0x%08lx 0x%08lx -f- %ld ber_memfree %ld\n",
   145â†’			(long)mh->bm_sequence, (long)mh, (long)mh->bm_length,
   146â†’			ber_int_meminuse);
   147â†’#endif
   148â†’		/* Fill the free space with poison */
   149â†’		memset( mh, 0xff, mh->bm_length + sizeof(struct ber_mem_hdr) + sizeof(ber_int_t));
   150â†’		free( mh );
   151â†’#else
   152â†’		free( p );
   153â†’#endif
   154â†’		return;
   155â†’	}
   156â†’
   157â†’	assert( ber_int_memory_fns->bmf_free != 0 );
   158â†’
   159â†’	(*ber_int_memory_fns->bmf_free)( p, ctx );
   160â†’}
   161â†’
   162â†’void
   163â†’ber_memfree( void *p )
   164â†’{
   165â†’	ber_memfree_x(p, NULL);
   166â†’}
   167â†’
   168â†’void
   169â†’ber_memvfree_x( void **vec, void *ctx )
   170â†’{
   171â†’	int	i;
   172â†’
   173â†’	if( vec == NULL ) {
   174â†’		return;
   175â†’	}
   176â†’
   177â†’	BER_MEM_VALID( vec );
   178â†’
   179â†’	for ( i = 0; vec[i] != NULL; i++ ) {
   180â†’		ber_memfree_x( vec[i], ctx );
   181â†’	}
   182â†’
   183â†’	ber_memfree_x( vec, ctx );
   184â†’}
   185â†’
   186â†’void
   187â†’ber_memvfree( void **vec )
   188â†’{
   189â†’	ber_memvfree_x( vec, NULL );
   190â†’}
   191â†’
   192â†’void *
   193â†’ber_memalloc_x( ber_len_t s, void *ctx )
   194â†’{
   195â†’	void *new;
   196â†’
   197â†’	if( s == 0 ) {
   198â†’		LDAP_MEMORY_DEBUG_ASSERT( s != 0 );
   199â†’		return NULL;
   200â†’	}
   201â†’
   202â†’	if( ber_int_memory_fns == NULL || ctx == NULL ) {
   203â†’#ifdef LDAP_MEMORY_DEBUG
   204â†’		new = malloc(s + sizeof(struct ber_mem_hdr) + sizeof( ber_int_t));
   205â†’		if( new )
   206â†’		{
   207â†’		struct ber_mem_hdr *mh = new;
   208â†’		mh->bm_top = LBER_MEM_JUNK;
   209â†’		mh->bm_length = s;
   210â†’		setdatatop( mh);
   211â†’		setend( (char *)&mh[1] + mh->bm_length );
   212â†’
   213â†’		ber_int_meminuse += mh->bm_length;	/* Count mem inuse */
   214â†’
   215â†’#ifdef LDAP_MEMORY_TRACE
   216â†’		mh->bm_sequence = sequence++;
   217â†’		fprintf(stderr, "0x%08lx 0x%08lx -a- %ld ber_memalloc %ld\n",
   218â†’			(long)mh->bm_sequence, (long)mh, (long)mh->bm_length,
   219â†’			ber_int_meminuse);
   220â†’#endif
   221â†’		/* poison new memory */
   222â†’		memset( (char *)&mh[1], 0xff, s);
   223â†’
   224â†’		BER_MEM_VALID( &mh[1] );
   225â†’		new = &mh[1];
   226â†’		}
   227â†’#else
   228â†’		new = malloc( s );
   229â†’#endif
   230â†’	} else {
   231â†’		new = (*ber_int_memory_fns->bmf_malloc)( s, ctx );
   232â†’	}
   233â†’
   234â†’	if( new == NULL ) {
   235â†’		ber_errno = LBER_ERROR_MEMORY;
   236â†’	}
