   247â†’void *
   248â†’ber_memcalloc_x( ber_len_t n, ber_len_t s, void *ctx )
   249â†’{
   250â†’	void *new;
   251â†’
   252â†’	if( n == 0 || s == 0 ) {
   253â†’		LDAP_MEMORY_DEBUG_ASSERT( n != 0 && s != 0);
   254â†’		return NULL;
   255â†’	}
   256â†’
   257â†’	if( ber_int_memory_fns == NULL || ctx == NULL ) {
   258â†’#ifdef LDAP_MEMORY_DEBUG
   259â†’		new = n < (-sizeof(struct ber_mem_hdr) - sizeof(ber_int_t)) / s
   260â†’			? calloc(1, n*s + sizeof(struct ber_mem_hdr) + sizeof(ber_int_t))
   261â†’			: NULL;
   262â†’		if( new )
   263â†’		{
   264â†’		struct ber_mem_hdr *mh = new;
   265â†’
   266â†’		mh->bm_top = LBER_MEM_JUNK;
   267â†’		mh->bm_length = n*s;
   268â†’		setdatatop( mh);
   269â†’		setend( (char *)&mh[1] + mh->bm_length );
   270â†’
   271â†’		ber_int_meminuse += mh->bm_length;
   272â†’
   273â†’#ifdef LDAP_MEMORY_TRACE
   274â†’		mh->bm_sequence = sequence++;
   275â†’		fprintf(stderr, "0x%08lx 0x%08lx -a- %ld ber_memcalloc %ld\n",
   276â†’			(long)mh->bm_sequence, (long)mh, (long)mh->bm_length,
   277â†’			ber_int_meminuse);
   278â†’#endif
   279â†’		BER_MEM_VALID( &mh[1] );
   280â†’		new = &mh[1];
   281â†’		}
   282â†’#else
   283â†’		new = calloc( n, s );
   284â†’#endif
   285â†’
   286â†’	} else {
   287â†’		new = (*ber_int_memory_fns->bmf_calloc)( n, s, ctx );
   288â†’	}
   289â†’
   290â†’	if( new == NULL ) {
   291â†’		ber_errno = LBER_ERROR_MEMORY;
   292â†’	}
   293â†’
   294â†’	return new;
   295â†’}
   296â†’
   297â†’void *
   298â†’ber_memcalloc( ber_len_t n, ber_len_t s )
   299â†’{
