   302â†’
   303â†’void *
   304â†’ber_memrealloc_x( void* p, ber_len_t s, void *ctx )
   305â†’{
   306â†’	void *new = NULL;
   307â†’
   308â†’	/* realloc(NULL,s) -> malloc(s) */
   309â†’	if( p == NULL ) {
   310â†’		return ber_memalloc_x( s, ctx );
   311â†’	}
   312â†’	
   313â†’	/* realloc(p,0) -> free(p) */
   314â†’	if( s == 0 ) {
   315â†’		ber_memfree_x( p, ctx );
   316â†’		return NULL;
   317â†’	}
   318â†’
   319â†’	BER_MEM_VALID( p );
   320â†’
   321â†’	if( ber_int_memory_fns == NULL || ctx == NULL ) {
   322â†’#ifdef LDAP_MEMORY_DEBUG
   323â†’		ber_int_t oldlen;
   324â†’		struct ber_mem_hdr *mh = (struct ber_mem_hdr *)
   325â†’			((char *)p - sizeof(struct ber_mem_hdr));
   326â†’		assert( mh->bm_top == LBER_MEM_JUNK);
   327â†’		assert( testdatatop( mh));
   328â†’		assert( testend( (char *)&mh[1] + mh->bm_length) );
   329â†’		oldlen = mh->bm_length;
   330â†’
   331â†’		p = realloc( mh, s + sizeof(struct ber_mem_hdr) + sizeof(ber_int_t) );
   332â†’		if( p == NULL ) {
   333â†’			ber_errno = LBER_ERROR_MEMORY;
   334â†’			return NULL;
   335â†’		}
   336â†’
   337â†’			mh = p;
   338â†’		mh->bm_length = s;
   339â†’		setend( (char *)&mh[1] + mh->bm_length );
   340â†’		if( s > oldlen ) {
   341â†’			/* poison any new memory */
   342â†’			memset( (char *)&mh[1] + oldlen, 0xff, s - oldlen);
   343â†’		}
   344â†’
   345â†’		assert( mh->bm_top == LBER_MEM_JUNK);
   346â†’		assert( testdatatop( mh));
   347â†’
   348â†’		ber_int_meminuse += s - oldlen;
   349â†’#ifdef LDAP_MEMORY_TRACE
   350â†’		fprintf(stderr, "0x%08lx 0x%08lx -a- %ld ber_memrealloc %ld\n",
   351â†’			(long)mh->bm_sequence, (long)mh, (long)mh->bm_length,
   352â†’			ber_int_meminuse);
   353â†’#endif
   354â†’			BER_MEM_VALID( &mh[1] );
   355â†’		return &mh[1];
   356â†’#else
   357â†’		new = realloc( p, s );
   358â†’#endif
   359â†’	} else {
   360â†’		new = (*ber_int_memory_fns->bmf_realloc)( p, s, ctx );
   361â†’	}
   362â†’
   363â†’	if( new == NULL ) {
   364â†’		ber_errno = LBER_ERROR_MEMORY;
   365â†’	}
   366â†’
   367â†’	return new;
   368â†’}
